async function seed() {
  console.log(`\n🌱 Iniciando seed de ${MOMENTOS.length} momentos...\n`)
  let sucesso = 0
  let erro = 0

  for (const m of MOMENTOS) {
    const { error } = await supabase
      .from('momento_kairos')
      .upsert(m, { onConflict: 'data' })

    if (error) {
      console.error(`❌ ${m.data}: ${error.message}`)
      erro++
    } else {
      console.log(`✓ ${m.data} — ${m.trilha} [${m.tom}]`)
      sucesso++
    }
  }

  console.log(`\n✅ Concluído: ${sucesso} inseridos, ${erro} erros\n`)
}

seed()
